// // This module implements a Deadbeat controller that delays the input by one clock cycle
module deadbeat_controller(  
    input clk,  
    input rst,  
    input [3:0] in,  
    output reg [3:0] out  
);  

always @(posedge clk or posedge rst) begin  
    if (rst)  
        out <= 4'b0000;  
    else  
        out <= in;  
end  
endmodule
